import React from 'react';
import { Calendar } from 'lucide-react-native';
import 'lucide-react-native/dist/style.css';

const HeroSection = () => {
  const [isHovered, setIsHovered] = React.useState(false);

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-zinc-900">
      <div className="container mx-auto p-4 md:p-6 lg:p-8">
        <div className="flex flex-col items-center justify-center">
          <h1 className="text-3xl md:text-5xl lg:text-7xl font-bold text-zinc-400 mb-4 md:mb-6 lg:mb-8 font-dm-sans">
            Veloce
          </h1>
          <p className="text-xl md:text-2xl lg:text-3xl text-zinc-400 mb-4 md:mb-6 lg:mb-8 font-dm-sans">
            Elevate Your Shopping Experience
          </p>
          <button
            className={`bg-zinc-600 hover:bg-zinc-700 text-zinc-400 py-2 md:py-3 lg:py-4 px-4 md:px-6 lg:px-8 rounded-md font-dm-sans transition duration-300 ${
              isHovered ? 'shadow-md' : 'shadow-none'
            }`}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
          >
            Explore Now
          </button>
          <div className="mt-4 md:mt-6 lg:mt-8">
            <Calendar size={24} color="#646464" />
          </div>
        </div>
      </div>
    </div>
  );
};

export default HeroSection;

