import React, { useState } from 'react';
import { FiChevronRight } from 'lucide-react-native';
import { View, Text } from 'react-native';
import { Link } from 'react-router-dom';

const CategoryShowcase = () => {
  const [activeTab, setActiveTab] = useState('all');
  const tabs = ['all', 'electronics', 'fashion', 'home'];

  return (
    <View className="bg-zinc-800 py-12 md:py-20 lg:py-24">
      <View className="container mx-auto px-4 sm:px-6 md:px-8 lg:px-12">
        <Text className="text-3xl md:text-4xl lg:text-5xl font-bold text-zinc-400 mb-4 md:mb-6 lg:mb-8">
          Browse Categories
        </Text>
        <View className="flex flex-wrap justify-center mb-4 md:mb-6 lg:mb-8">
          {tabs.map((tab) => (
            <View
              key={tab}
              className={`py-2 md:py-3 lg:py-4 px-4 md:px-6 lg:px-8 bg-zinc-700 hover:bg-zinc-600 rounded-md cursor-pointer mr-2 md:mr-4 lg:mr-6 ${
                activeTab === tab ? 'bg-zinc-600' : ''
              }`}
              onClick={() => setActiveTab(tab)}
            >
              <Text className="text-zinc-400 text-lg md:text-xl lg:text-2xl font-bold">
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
              </Text>
            </View>
          ))}
        </View>
        <View className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6 lg:gap-8">
          {[1, 2, 3, 4, 5, 6, 7, 8].map((item) => (
            <Link
              key={item}
              to={`/category/${activeTab}`}
              className="block bg-zinc-700 hover:bg-zinc-600 rounded-md p-4 md:p-6 lg:p-8"
            >
              <Text className="text-zinc-400 text-lg md:text-xl lg:text-2xl font-bold mb-2 md:mb-4 lg:mb-6">
                Category {item}
              </Text>
              <Text className="text-zinc-500 text-base md:text-lg lg:text-xl">
                Description for category {item}
              </Text>
              <View className="flex justify-end mt-4 md:mt-6 lg:mt-8">
                <FiChevronRight size={24} color="#94A3B8" />
              </View>
            </Link>
          ))}
        </View>
      </View>
    </View>
  );
};

export default CategoryShowcase;

