import React, { useState } from 'react';
import { FiGrid, FiList } from 'lucide-react';

const ProductGrid = () => {
  const [view, setView] = useState('grid');
  const [products, setProducts] = useState([
    { id: 1, name: 'Product 1', price: 19.99 },
    { id: 2, name: 'Product 2', price: 9.99 },
    { id: 3, name: 'Product 3', price: 29.99 },
    { id: 4, name: 'Product 4', price: 39.99 },
    { id: 5, name: 'Product 5', price: 49.99 },
    { id: 6, name: 'Product 6', price: 59.99 },
    { id: 7, name: 'Product 7', price: 69.99 },
    { id: 8, name: 'Product 8', price: 79.99 },
  ]);

  const handleViewChange = (viewType) => {
    setView(viewType);
  };

  return (
    <div className="container mx-auto p-4 md:p-6 lg:p-8">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-2xl font-bold text-zinc-200">Products</h2>
        <div className="flex items-center">
          <button
            onClick={() => handleViewChange('grid')}
            className={`p-2 rounded-md ${view === 'grid' ? 'bg-zinc-600 text-zinc-200' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
          >
            <FiGrid size={20} />
          </button>
          <button
            onClick={() => handleViewChange('list')}
            className={`p-2 rounded-md ${view === 'list' ? 'bg-zinc-600 text-zinc-200' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
          >
            <FiList size={20} />
          </button>
        </div>
      </div>
      {view === 'grid' ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
          {products.map((product) => (
            <div key={product.id} className="bg-zinc-800 rounded-md p-4">
              <h3 className="text-zinc-200 text-lg font-bold">{product.name}</h3>
              <p className="text-zinc-400">${product.price}</p>
            </div>
          ))}
        </div>
      ) : (
        <div className="flex flex-col">
          {products.map((product) => (
            <div key={product.id} className="bg-zinc-800 rounded-md p-4 mb-4">
              <h3 className="text-zinc-200 text-lg font-bold">{product.name}</h3>
              <p className="text-zinc-400">${product.price}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ProductGrid;

